-- PostgreSQL: Chuẩn hóa, dùng JOIN
CREATE TABLE orders   (id BIGINT, user_id BIGINT, total DECIMAL);
CREATE TABLE order_items (order_id BIGINT, sku_id BIGINT, qty INT, unit_price DECIMAL);

SELECT o.id, oi.sku_id, oi.qty
FROM orders o JOIN order_items oi ON oi.order_id = o.id
WHERE o.id = 42;

// MongoDB: Denormalize, nhúng items vào document
db.orders.insertOne({
  _id: 42,
  user_id: 7,
  total: 350000,
  items: [
    { sku_id: 'AT-M-RED', qty: 2, unit_price: 120000 },
    { sku_id: 'QT-L-BLK', qty: 1, unit_price: 110000 }
  ]
});

db.orders.findOne({ _id: 42 }); // Đọc 1 lần, không JOIN

-- Cách 1: TSVECTOR column (nhanh nhất)
ALTER TABLE products
  ADD COLUMN text_search TSVECTOR
    GENERATED ALWAYS AS (
      to_tsvector('english', name || ' ' || COALESCE(description, ''))
    ) STORED;

CREATE INDEX idx_gin_search ON products USING GIN(text_search);

SELECT * FROM products
WHERE text_search @@ to_tsquery('english', 'iphone & pro')
ORDER BY ts_rank(text_search, to_tsquery('iphone & pro')) DESC;

-- Cách 2: pg_trgm — tốt cho tiếng Việt & LIKE fuzzy
CREATE EXTENSION IF NOT EXISTS pg_trgm;
CREATE INDEX idx_trgm_name ON products USING GIN(name gin_trgm_ops);

-- Giờ LIKE '%iphone%' DÙNG ĐƯỢC index!
SELECT * FROM products WHERE name ILIKE '%điện thoại%';

-- MYSQL FULLTEXT (built-in, đơn giản)
MATCH(name) AGAINST('iphone' IN BOOLEAN MODE)
-- ✅ Đơn giản  ❌ Tiếng Việt kém  ❌ Scale giới hạn

-- POSTGRESQL pg_trgm (flexible, trong DB)
WHERE name ILIKE '%điện thoại%'  -- dùng được GIN index
-- ✅ Tiếng Việt OK  ✅ LIKE có index  ❌ Không bằng ES về relevance

-- ELASTICSEARCH (production-grade search)
// Node.js client
const results = await es.search({
  index: 'products',
  body: {
    query: {
      multi_match: {
        query: 'điện thoại samsung',
        fields: ['name^3', 'description'],  // name ưu tiên gấp 3
        fuzziness: 'AUTO'  // 'samsug' vẫn tìm được 'samsung'
      }
    }
  }
});
// ✅ Tiếng Việt  ✅ Fuzzy  ✅ Scale  ❌ Cần sync data từ DB
